# Real axis: -6 to 1, Imag axis: -4 to 4
S_REAL_MIN, S_REAL_MAX = -6.0, 1.0
S_IMAG_MIN, S_IMAG_MAX = -4.0, 4.0


def s_to_pixel(sigma, omega, rect):
    """Convert s-plane coordinates to pixel coordinates."""
    px = rect.x + (sigma - S_REAL_MIN) / (S_REAL_MAX - S_REAL_MIN) * rect.width
    py = rect.y + (1.0 - (omega - S_IMAG_MIN) / (S_IMAG_MAX - S_IMAG_MIN)) * rect.height
    return int(px), int(py)


def pixel_to_s(px, py, rect):
    """Convert pixel coordinates to s-plane coordinates."""
    sigma = S_REAL_MIN + (px - rect.x) / rect.width * (S_REAL_MAX - S_REAL_MIN)
    omega = S_IMAG_MIN + (1.0 - (py - rect.y) / rect.height) * (S_IMAG_MAX - S_IMAG_MIN)
    return sigma, omega


def compute_transfer_function(sigma, omega_n):
    """
    Poles at sigma +/- j*omega_n
    H(s) = omega_n^2 + sigma^2 / ((s - p1)(s - p2))
    = K / (s^2 - 2*sigma*s + (sigma^2 + omega_n^2))
    where K = sigma^2 + omega_n^2 (DC gain = 1)
    """
    # Denominator coefficients: s^2 + a1*s + a0
    a1 = -2.0 * sigma  # coefficient of s
    a0 = sigma ** 2 + omega_n ** 2  # constant term
    K = a0  # so DC gain = 1
    return K, a1, a0


def compute_bode(sigma, omega_n, num_points=300):
    """Compute Bode magnitude and phase."""
    K, a1, a0 = compute_transfer_function(sigma, omega_n)

    # Frequency range
    w_min = 0.01
    w_max = 100.0
    w = np.logspace(np.log10(w_min), np.log10(w_max), num_points)

    # H(jw) = K / ((jw)^2 + a1*(jw) + a0)
    # = K / (-w^2 + j*a1*w + a0)
    # = K / ((a0 - w^2) + j*a1*w)

    real_part = a0 - w ** 2
    imag_part = a1 * w

    denom_mag_sq = real_part ** 2 + imag_part ** 2
    denom_mag_sq = np.maximum(denom_mag_sq, 1e-30)

    mag = np.abs(K) / np.sqrt(denom_mag_sq)
    mag_db = 20.0 * np.log10(np.maximum(mag, 1e-15))

    phase_rad = np.arctan2(-imag_part, real_part)  # angle of denominator negated
    phase_deg = np.degrees(phase_rad)

    return w, mag_db, phase_deg


def compute_step_response(sigma, omega_n, t_max=10.0, num_points=500):
    """Compute step response using inverse Laplace / time domain formula."""
    K, a1, a0 = compute_transfer_function(sigma, omega_n)
    t = np.linspace(0, t_max, num_points)

    # Poles: p = sigma +/- j*omega_n
    # Step response of H(s)/s
    # H(s) = K / (s^2 + a1*s + a0)
    # Y(s) = H(s)/s = K / (s*(s^2 + a1*s + a0))

    # Partial fractions: Y(s) = A/s + (Bs + C)/(s^2 + a1*s + a0)
    # A = K/a0 (DC gain)
    # At s=0: A*a0 = K => A = K/a0 = 1 (since K=a0)

    A = K / a0  # = 1.0

    # Remaining: Y(s) - A/s = (K - A*(s^2 + a1*s + a0)) / (s*(s^2 + a1*s + a0))
    # = (-A*s^2 - A*a1*s) / (s*(s^2 + a1*s + a0))
    # = (-A*s - A*a1) / (s^2 + a1*s + a0)
    # = -(A*s + A*a1) / (s^2 + a1*s + a0)

    # So y(t) = A*u(t) + inverse_laplace[-(A*s + A*a1)/(s^2 + a1*s + a0)]

    # s^2 + a1*s + a0 = (s - sigma)^2 + omega_n^2
    # where sigma = -a1/2, omega_d = omega_n (imaginary part)

    sigma_p = -a1 / 2.0  # = sigma (the real part of poles)
    omega_d = omega_n  # damped natural frequency

    if abs(omega_d) < 1e-6:
        # Repeated real poles
        y = A * (1.0 - np.exp(sigma_p * t) * (1.0 - sigma_p * t))
    else:
        # Complex poles
        # inverse_laplace[-(A*s + A*a1)/(s^2 + a1*s + a0)]
        # = -A * e^(sigma_p*t) * [cos(omega_d*t) + (a1 + 2*sigma_p)/omega_d * sin(omega_d*t)/2... ]
        # Let's use: -(A*s + A*a1) = -A*(s + a1)
        # = -A*((s - sigma_p) + (a1 + sigma_p))
        # = -A*((s - sigma_p) + sigma_p)  since a1 = -2*sigma_p => a1 + sigma_p = -sigma_p
        # Wait: a1 = -2*sigma_p, so a1 + sigma_p = -sigma_p

        # inverse_laplace[-A*(s-sigma_p)/((s-sigma_p)^2+omega_d^2)] = -A*e^(sigma_p*t)*cos(omega_d*t)
        # inverse_laplace[-A*sigma_p/((s-sigma_p)^2+omega_d^2)] = -A*sigma_p/omega_d * e^(sigma_p*t)*sin(omega_d*t)

        cos_term = -A * np.exp(sigma_p * t) * np.cos(omega_d * t)
        sin_term = -A * (sigma_p / omega_d) * np.exp(sigma_p * t) * np.sin(omega_d * t)

        y = A + cos_term + sin_term

    return t, y


