def draw_step_response(surface, rect, t, y):
    """Draw step response."""
    draw_panel(surface, rect, "Step Response")

    plot_rect = pygame.Rect(rect.x + 45, rect.y + 25, rect.width - 55, rect.height - 45)
    pygame.draw.rect(surface, (10, 10, 20), plot_rect)

    # Y range
    y_min = min(-0.2, np.min(y) - 0.1) if len(y) > 0 else -0.2
    y_max = max(2.0, np.max(y) + 0.1) if len(y) > 0 else 2.0
    y_range = y_max - y_min

    # Grid
    for y_val in np.arange(0, y_max + 0.5, 0.5):
        py = plot_rect.y + (1.0 - (y_val - y_min) / y_range) * plot_rect.height
        if plot_rect.y <= py <= plot_rect.bottom:
            pygame.draw.line(surface, GRID_COLOR, (plot_rect.x, int(py)), (plot_rect.right, int(py)), 1)
            lbl = font_small.render(f"{y_val:.1f}", True, AXIS_COLOR)
            surface.blit(lbl, (rect.x + 2, int(py) - 7))

    # Reference line at y=1
    py1 = plot_rect.y + (1.0 - (1.0 - y_min) / y_range) * plot_rect.height
    if plot_rect.y <= py1 <= plot_rect.bottom:
        pygame.draw.line(surface, (80, 80, 120), (plot_rect.x, int(py1)), (plot_rect.right, int(py1)), 1)

    # Time grid
    t_max = t[-1] if len(t) > 0 else 10.0
    for t_val in np.arange(0, t_max + 1, 2):
        px = plot_rect.x + (t_val / t_max) * plot_rect.width
        if plot_rect.x <= px <= plot_rect.right:
            pygame.draw.line(surface, GRID_COLOR, (int(px), plot_rect.y), (int(px), plot_rect.bottom), 1)
            lbl = font_small.render(f"{t_val:.0f}", True, AXIS_COLOR)
            surface.blit(lbl, (int(px) - 8, plot_rect.bottom + 2))

    # Plot step response
    points = []
    for ti, yi in zip(t, y):
        px = plot_rect.x + (ti / t_max) * plot_rect.width
        py = plot_rect.y + (1.0 - (yi - y_min) / y_range) * plot_rect.height
        py = max(plot_rect.y, min(plot_rect.bottom, py))
        points.append((int(px), int(py)))

    if len(points) > 1:
        pygame.draw.lines(surface, STEP_COLOR, False, points, 2)

    # Labels
    lbl_x = font_small.render("Time (s)", True, AXIS_COLOR)
    lbl_y = font_small.render("y(t)", True, AXIS_COLOR)
    surface.blit(lbl_x, (plot_rect.right - 50, plot_rect.bottom + 2))
    surface.blit(lbl_y, (rect.x + 2, rect.y + 25))


def draw_info(surface, rect, sigma, omega_n):
    """Draw system information panel."""
    draw_panel(surface, rect, "System Information")

    K, a1, a0 = compute_transfer_function(sigma, omega_n)

    # Compute system parameters
    wn = np.sqrt(sigma ** 2 + omega_n ** 2)  # natural frequency
    if wn > 1e-6:
        zeta = -sigma / wn  # damping ratio
    else:
        zeta = 0.0

    # Stability
    stable = sigma < 0
    stable_str = "STABLE ✓" if stable else "UNSTABLE ✗"
    stable_color = (0, 200, 0) if stable else (200, 0, 0)

    lines = [
        f"Poles: {sigma:.3f} ± {omega_n:.3f}j",
        f"",
        f"Transfer Function:",
        f"  H(s) = {K:.3f}",
        f"         ─────────────────────",
        f"         s² + {a1:.3f}s + {a0:.3f}",
        f"",
        f"Natural Freq (ωn): {wn:.3f} rad/s",
        f"Damping Ratio (ζ): {zeta:.3f}",
        f"Damped Freq (ωd):  {abs(omega_n):.3f} rad/s",
        f"",
        f"Status: {stable_str}",
        f"",
        f"Controls:",
        f"  Drag poles to move",
        f"  Poles move as conjugate pair",
    ]

    y_offset = rect.y + 28
    for i, line in enumerate(lines):
        color = stable_color if "Status" in line else TEXT_COLOR
        if "Status" in line:
            surf = font_med.render(line, True, color)
        else:
            surf = font_small.render(line, True, color)
        surface.blit(surf, (rect.x + 10, y_offset))
        y_offset += 16


def main():
    print("Starting S-Plane Pole Mover with Bode Plot & Step Response")
    print("Drag the poles (X marks) in the S-plane to see real-time updates!")

    clock = pygame.time.Clock()

    # Initial pole position: sigma=-1, omega_n=2 (underdamped)
    sigma = -1.0
    omega_n = 2.0

    dragging = False

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_ESCAPE:
                    running = False
                elif event.key == pygame.K_r:
                    # Reset to default
                    sigma = -1.0
                    omega_n = 2.0
                    print(f"Reset poles to sigma={sigma}, omega_n={omega_n}")

            elif event.type == pygame.MOUSEBUTTONDOWN:
                if event.button == 1:
                    mx, my = event.pos
                    # Check if clicking near either pole
                    px1, py1 = s_to_pixel(sigma, omega_n, SPLANE_RECT)
                    px2, py2 = s_to_pixel(sigma, -omega_n, SPLANE_RECT)

                    dist1 = np.sqrt((mx - px1) ** 2 + (my - py1) ** 2)
                    dist2 = np.sqrt((mx - px2) ** 2 + (my - py2) ** 2)

                    if dist1 < 20 or dist2 < 20:
                        dragging = True

            elif event.type == pygame.MOUSEBUTTONUP:
                if event.button == 1:
                    dragging = False

            elif event.type == pygame.MOUSEMOTION:
                if dragging:
                    mx, my = event.pos
                    # Convert mouse position to s-plane coordinates
                    new_sigma, new_omega = pixel_to_s(mx, my, SPLANE_RECT)

                    # Clamp to valid range
                    new_sigma = max(S_REAL_MIN + 0.1, min(S_REAL_MAX - 0.1, new_sigma))
                    new_omega = max(0.01, min(S_IMAG_MAX - 0.1, abs(new_omega)))

                    sigma = new_sigma
                    omega_n = new_omega

        # Compute data
        try:
            w, mag_db, phase_deg = compute_bode(sigma, omega_n)
            t, y = compute_step_response(sigma, omega_n)
        except Exception as e:
            print(f"Computation error: {e}")
            w = np.logspace(-2, 2, 300)
            mag_db = np.zeros(300)
            phase_deg = np.zeros(300)
            t = np.linspace(0, 10, 500)
            y = np.zeros(500)

        # Draw everything
        screen.fill(BG_COLOR)

        draw_splane(screen, SPLANE_RECT, sigma, omega_n, dragging)
        draw_bode_mag(screen, BODE_MAG_RECT, w, mag_db)
        draw_bode_phase(screen, BODE_PHASE_RECT, w, phase_deg)
        draw_step_response(screen, STEP_RECT, t, y)
        draw_info(screen, INFO_RECT, sigma, omega_n)

        # Title bar info
        title_surf = font_med.render(
            f"σ={sigma:.2f}  ωd={omega_n:.2f}  |  Press R to reset, ESC to quit",
            True, (150, 150, 180)
        )
        screen.blit(title_surf, (510, 500))

        pygame.display.flip()
        clock.tick(60)

    pygame.quit()
    print("Application closed.")
    sys.exit()


if __name__ == "__main__":
    main()